def find_city(n, edges, T):
    INF = 10**12
    dist = [[INF]*n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
    for u, v, w in edges:
        if w < dist[u][v]:
            dist[u][v] = dist[v][u] = w
    for k in range(n):
        dk = dist[k]
        for i in range(n):
            di = dist[i]
            dik = di[k]
            if dik >= INF: 
                continue
            for j in range(n):
                if dk[j] + dik < di[j]:
                    di[j] = dk[j] + dik
    best = -1
    bestCnt = 10**9
    for i in range(n):
        cnt = sum(1 for j in range(n) if i != j and dist[i][j] <= T)
        if cnt <= bestCnt:
            bestCnt = cnt
            best = i
    return best

